+/// Pending tab add - stored for deferred processing to avoid data races
+/// CDP thread sets this, main loop processes it
+const PendingTabAdd = struct {
+    target_id: [128]u8,
+    target_id_len: u8,
+    url: [2048]u8,
+    url_len: u16,
+    title: [256]u8,
+    title_len: u8,
+    auto_switch: bool, // Whether to switch to this tab after adding
+};
+
